UPDATE product_sku
SET stock = stock - #{quantity}
WHERE id = #{skuId}
  AND stock >= #{quantity}
  AND deleted = 0
  AND status = 'ON'

UPDATE product_sku
SET stock = stock + #{quantity}
WHERE id = #{skuId}
  AND deleted = 0

mapper.select:
SELECT spu_id, MIN(price) AS min_price, MAX(price) AS max_price, SUM(stock) AS total_stock FROM product_sku WHERE deleted = 0 AND status = 'ON' AND spu_id IN
#{id}
GROUP BY spu_id

SELECT
    s.id AS spu_id,
    MIN(k.price) AS min_price
FROM product_spu s
         JOIN product_sku k ON s.id = k.spu_id
WHERE s.deleted = 0
  AND s.status = 'ON'
  AND k.deleted = 0
  AND k.status = 'ON'

    AND s.name LIKE CONCAT('%', #{req.keyword}, '%')


    AND s.category_id = #{req.categoryId}


    AND k.color IN

        #{item}



    AND k.color = #{req.color}


    AND k.size = #{req.size}


    AND k.fit_type = #{req.fitType}


    AND k.price >= #{req.minPrice}


    AND k.price <= #{req.maxPrice}


    AND k.stock > 0


    AND k.length_cm >= #{req.lengthMin}


    AND k.length_cm <= #{req.lengthMax}


    AND k.waist_cm >= #{req.waistMin}


    AND k.waist_cm <= #{req.waistMax}


    AND k.leg_opening_cm >= #{req.legOpeningMin}


    AND k.leg_opening_cm <= #{req.legOpeningMax}

GROUP BY s.id
ORDER BY min_price

    DESC

SELECT spu_id, MIN(price) AS min_price, MAX(price) AS max_price, SUM(stock) AS total_stock, MIN(waist_cm) AS min_waist_cm, MAX(waist_cm) AS max_waist_cm, MIN(length_cm) AS min_length_cm, MAX(length_cm) AS max_length_cm, MIN(leg_opening_cm) AS min_leg_opening_cm, MAX(leg_opening_cm) AS max_leg_opening_cm, GROUP_CONCAT(DISTINCT color ORDER BY color SEPARATOR ',') AS colors, GROUP_CONCAT(DISTINCT size ORDER BY size SEPARATOR ',') AS sizes, GROUP_CONCAT(DISTINCT fit_type ORDER BY fit_type SEPARATOR ',') AS fit_types FROM product_sku WHERE deleted = 0 AND status = 'ON' AND spu_id IN
#{id}
GROUP BY spu_id

SELECT id, spu_id, sku_code, title, price, stock, color, size, status, length_cm, waist_cm, leg_opening_cm, fit_type, created_at, updated_at, deleted FROM product_sku
deleted = 0 AND status = 'ON' AND stock > 0
AND spu_id = #{spuId}
AND color = #{color}
AND size = #{size}
AND fit_type = #{fitType}
AND length_cm = #{lengthCm}
AND waist_cm = #{waistCm}
AND leg_opening_cm = #{legOpeningCm}
AND price >= #{minPrice}
AND price <= #{maxPrice}
ORDER BY price ASC, length_cm ASC, size ASC
